 14→// runSessionStart outputs JSON with systemMessage (visible banner) and
 15→// additionalContext (LLM context) for the SessionStart hook.
 16→// Also captures the session in DB + log.
 17→func runSessionStart() error {
 18→	// Read stdin (Claude Code sends session info)
 19→	input, _ := session.ReadStdin()
 20→
 21→	// Sync permissions — ensures existing users get any new permissions
 22→	// added in later versions. Graceful — never fails the hook.
 23→	project.SyncPermissions()
 24→
 25→	syncReport := attemptSessionStartSync()
 26→
 27→	// Auto-update check (non-blocking, cached)
 28→	updateMsg := checkAndAutoUpdate()
 29→
 30→	s := gatherStatus()
 31→	s.startSync = syncReport
 32→
 33→	// Capture session + sync event in a single DB open (graceful — don't fail the hook)
 34→	if input != nil && input.SessionID != "" && db.Exists() {
 35→		if d, err := db.Open(); err == nil {
 36→
 37→			session.CreateSession(d, input.SessionID, input.Model, input.Source, input.TranscriptPath)
 38→			session.AddEvent(d, input.SessionID, "session_start", input)
 39→			if syncReport != nil && syncReport.Attempted {
 40→				session.AddEvent(d, input.SessionID, "sync_pull", syncReport)
 41→			}
 42→			d.Close()
 43→		}
 44→		session.Logger().Info("session-start", "session_id", input.SessionID, "model", input.Model)
 45→		session.FlushLog()
 46→	}
 47→
 48→	banner := buildBanner(s)
 49→	if updateMsg != "" {
 50→		banner += "\n  " + updateMsg
 51→	}
 52→	context := buildPromptContext(s)
 53→
 54→	out := hookOutput{
 55→		SystemMessage: banner,
 56→		HookSpecificOut: &hookSpecificOut{
 57→			HookEventName:     "SessionStart",
 58→			AdditionalContext: context,
 59→		},
 60→	}
 61→
 62→	enc := json.NewEncoder(os.Stdout)
 63→	return enc.Encode(out)
 64→}
 65→
 66→// openSessionDB reads hook stdin, opens the DB, and ensures session tables.
 67→// Returns (nil, nil, nil) when the hook should silently no-op.
 68→func openSessionDB() (*sql.DB, *session.HookInput, error) {
 69→	input, err := session.ReadStdin()
 70→	if err != nil || input == nil || input.SessionID == "" {
 71→		return nil, nil, nil
 72→	}
 73→	if !db.Exists() {
 74→		return nil, nil, nil
 75→	}
 76→	d, err := db.Open()
 77→	if err != nil {
 78→		return nil, nil, nil
 79→	}
 80→	return d, input, nil
 81→}
 82→
 83→// runUserPrompt captures a user prompt submission event.
 84→func runUserPrompt() error {
 85→	d, input, _ := openSessionDB()
 86→	if d == nil {
 87→		return nil
 88→	}
 89→	defer d.Close()
 90→
 91→	session.AddEvent(d, input.SessionID, "prompt", input)
 92→	session.Logger().Info("prompt", "session_id", input.SessionID)
 93→	session.FlushLog()
 94→	return nil
 95→}
 96→
 97→// runStop captures a stop event and creates a checkpoint.
 98→func runStop() error {
 99→	d, input, _ := openSessionDB()
100→	if d == nil {
101→		return nil
102→	}
103→	defer d.Close()
104→
105→	session.AddEvent(d, input.SessionID, "stop", input)
106→	if len(input.ModifiedFiles) > 0 {
107→		session.AddCheckpoint(d, input.SessionID, input.ModifiedFiles)
108→	}
109→
110→	session.Logger().Info("stop", "session_id", input.SessionID, "reason", input.StopReason)
111→	session.FlushLog()
112→	return nil
113→}
114→
115→// runSessionEnd marks a session as ended.
116→func runSessionEnd() error {
117→	d, input, _ := openSessionDB()
118→	if d == nil {
119→		return nil
120→	}
121→	defer d.Close()
122→
123→	session.EndSession(d, input.SessionID)
124→	session.AddEvent(d, input.SessionID, "session_end", input)
125→
126→	pushReport := attemptSessionEndPush(d)
127→	if pushReport.Attempted {
128→		session.AddEvent(d, input.SessionID, "sync_push", pushReport)
129→		if pushReport.Error != "" {
130→			session.Logger().Info("session-sync-push", "session_id", input.SessionID, "error", pushReport.Error)
131→		} else {
132→			session.Logger().Info("session-sync-push", "session_id", input.SessionID, "rows_pushed", pushReport.RowsPushed)
133→		}
134→	}
135→
136→	session.Logger().Info("session-end", "session_id", input.SessionID)
137→	session.FlushLog()
138→	return nil
139→}
