 15→var metricsCmd = &cobra.Command{
 16→	Use:         "metrics",
 17→	Short:       "Show context token usage metrics",
 18→	Long:        "Track how many tokens each CLI command contributes to Claude's context window.",
 19→	Annotations: map[string]string{"skipAuth": "true"},
 20→	RunE: func(cmd *cobra.Command, args []string) error {
 21→		d, err := db.Open()
 22→		if err != nil {
 23→			return err
 24→		}
 25→		defer d.Close()
 26→
 27→		if err := metrics.EnsureTable(d); err != nil {
 28→			return err
 29→		}
 30→
 31→		sid := metrics.SessionID()
 32→		summary, err := metrics.Summary(d, sid)
 33→		if err != nil {
 34→			return err
 35→		}
 36→
 37→		if metricsFormat == "json" {
 38→			enc := json.NewEncoder(os.Stdout)
 39→			enc.SetIndent("", "  ")
 40→			return enc.Encode(summary)
 41→		}
 42→
 43→		if summary.CommandCount == 0 {
 44→			fmt.Println("  No metrics recorded for current session.")
 45→			return nil
 46→		}
 47→
 48→		fmt.Printf("  Session: %s\n", sid)
 49→		fmt.Printf("  Commands: %d  |  Total: %s (~%d tokens)\n\n",
 50→			summary.CommandCount, metrics.FormatBytes(summary.TotalBytes), summary.TotalTokens)
 51→		fmt.Printf("  %-30s %6s %10s %8s\n", "COMMAND", "CALLS", "BYTES", "TOKENS")
 52→		fmt.Printf("  %-30s %6s %10s %8s\n", "-------", "-----", "-----", "------")
 53→		for _, cs := range summary.ByCommand {
 54→			fmt.Printf("  %-30s %6d %10s %8d\n",
 55→				cs.Command, cs.Calls, metrics.FormatBytes(cs.TotalBytes), cs.TotalTokens)
 56→		}
 57→		return nil
 58→	},
 59→}
