 14→var tierFormat string
 15→var tierProspect string
 16→var tierBatch bool
 17→var tierLimit int
 18→var tierShow bool
 19→
 20→var tierCmd = &cobra.Command{
 21→	Use:   "tier",
 22→	Short: "Score and tier contacts based on ICP fit",
 23→	Long:  "Score contacts using ICP fit, buying triggers, intent signals, and accessibility.\nAssigns Tier 1 (>=70), Tier 2 (>=40), or Tier 3 (<40).",
 24→	RunE: func(cmd *cobra.Command, args []string) error {
 25→		if !tierShow && !tierBatch && tierProspect == "" {
 26→			return cmd.Help()
 27→		}
 28→
 29→		d, err := db.Open()
 30→		if err != nil {
 31→			return err
 32→		}
 33→		defer d.Close()
 34→
 35→		if tierShow {
 36→			return runTierShow(d)
 37→		}
 38→
 39→		if tierProspect != "" {
 40→			return runTierProspectCmd(d, tierProspect)
 41→		}
 42→
 43→		if tierBatch {
 44→			return runTierBatch(d, tierLimit)
 45→		}
 46→
 47→		return nil
 48→	},
 49→}
 50→
 51→func runTierProspectCmd(d *sql.DB, email string) error {
 52→	score, err := tier.ScoreAndSave(d, email)
 53→	if err != nil {
 54→		return err
 55→	}
 56→
 57→	if tierFormat == "json" {
 58→		enc := json.NewEncoder(os.Stdout)
 59→		enc.SetIndent("", "  ")
 60→		return enc.Encode(score)
 61→	}
 62→
 63→	fmt.Printf("  Tier %d  (score: %.1f)\n", score.Tier, score.Total)
 64→	fmt.Printf("  ICP Fit: %.0f  |  Buying Trigger: %.0f  |  Intent: %.0f  |  Accessibility: %.0f\n",
 65→		score.ICPFit, score.BuyingTrigger, score.IntentSignal, score.Accessibility)
 66→	if len(score.Reasons) > 0 {
 67→		fmt.Println("  Reasons:")
 68→		for _, r := range score.Reasons {
 69→			fmt.Printf("    - %s\n", r)
 70→		}
 71→	}
 72→	return nil
 73→}
 74→
 75→func runTierShow(d *sql.DB) error {
 76→	dist, err := tier.Distribution(d)
 77→	if err != nil {
 78→		return err
 79→	}
 80→
 81→	if tierFormat == "json" {
 82→		enc := json.NewEncoder(os.Stdout)
 83→		enc.SetIndent("", "  ")
 84→		return enc.Encode(dist)
 85→	}
 86→
 87→	fmt.Printf("  Tier Distribution (%d contacts)\n", dist.Total)
 88→	fmt.Printf("  ──────────────────────────────\n")
 89→	fmt.Printf("  Tier 1 (hot):       %d\n", dist.Tier1)
 90→	fmt.Printf("  Tier 2 (warm):      %d\n", dist.Tier2)
 91→	fmt.Printf("  Tier 3 (cold):      %d\n", dist.Tier3)
 92→	fmt.Printf("  Unscored:           %d\n", dist.Unscored)
 93→	return nil
 94→}
 95→
 96→func runTierBatch(d *sql.DB, limit int) error {
 97→	results, err := tier.BatchScore(d, limit)
 98→	if err != nil {
 99→		return err
100→	}
101→
102→	if tierFormat == "json" {
103→		enc := json.NewEncoder(os.Stdout)
104→		enc.SetIndent("", "  ")
105→		return enc.Encode(results)
106→	}
107→
108→	if len(results) == 0 {
109→		fmt.Println("  No contacts to score.")
110→		return nil
111→	}
112→
113→	fmt.Printf("  Scored %d contact(s):\n", len(results))
114→	for _, r := range results {
115→		label := "cold"
116→		if r.Score.Tier == 1 {
117→			label = "hot"
118→		} else if r.Score.Tier == 2 {
119→			label = "warm"
120→		}
121→		name := r.Name
122→		if name == "" {
123→			name = r.Email
124→		}
125→		fmt.Printf("    [T%d %s] %s  (%.1f)\n", r.Score.Tier, label, name, r.Score.Total)
126→	}
127→	return nil
128→}
129→
130→func init() {
131→	tierCmd.Flags().StringVar(&tierFormat, "format", "", "Output format (json)")
132→	tierCmd.Flags().StringVar(&tierProspect, "prospect", "", "Score a single contact by email")
133→	tierCmd.Flags().BoolVar(&tierBatch, "batch", false, "Score all unscored contacts")
134→	tierCmd.Flags().IntVar(&tierLimit, "limit", 50, "Max contacts to score in batch mode")
135→	tierCmd.Flags().BoolVar(&tierShow, "show", false, "Show tier distribution")
136→}
