307→func buildSkillRefreshBannerLine(staleSkills []session.StaleSkill) string {
308→	if len(staleSkills) == 0 {
309→		return ""
310→	}
311→	names := make([]string, 0, len(staleSkills))
312→	for i, item := range staleSkills {
313→		if i >= 3 {
314→			break
315→		}
316→		names = append(names, item.SkillName)
317→	}
318→	return fmt.Sprintf("Skills ready for refresh: %s", strings.Join(names, ", "))
319→}
