360→func pluralSuffix(count int, forms ...string) string {
361→	if len(forms) == 2 {
362→		if count == 1 {
363→			return forms[0]
364→		}
365→		return forms[1]
366→	}
367→	if count == 1 {
368→		return ""
369→	}
370→	return "s"
371→}
