 28→var sendCmd = &cobra.Command{
 29→	Use:   "send",
 30→	Short: "Send an email via Gmail API",
 31→	Long:  "Send an email through your connected Gmail account directly via the Gmail API.",
 32→	RunE: func(cmd *cobra.Command, args []string) error {
 33→		if sendSequence != "" && sendTaskID != "" {
 34→			return fmt.Errorf("--sequence and --task-id cannot be used together")
 35→		}
 36→
 37→		// Get connected Gmail account
 38→		cfg, err := project.Load()
 39→		if err != nil {
 40→			return fmt.Errorf("loading config: %w", err)
 41→		}
 42→		gmail, ok := cfg.Connectors["gmail"]
 43→		if !ok || !gmail.Connected {
 44→			return fmt.Errorf("Gmail not connected. Run: nurge connect gmail")
 45→		}
 46→		fromAddress := gmail.Account
 47→
 48→		// Create Gmail API client
 49→		srv, err := email.NewClient("")
 50→		if err != nil {
 51→			return fmt.Errorf("creating Gmail client: %w", err)
 52→		}
 53→
 54→		d, err := db.Open()
 55→		if err != nil {
 56→			return fmt.Errorf("opening database: %w", err)
 57→		}
 58→		defer d.Close()
 59→
 60→		// If --task-id is provided, resolve draft content from local DB
 61→		if sendTaskID != "" {
 62→			task, err := sequence.TaskByID(d, sendTaskID)
 63→			if err != nil {
 64→				return err
 65→			}
 66→			if sendTo == "" {
 67→				sendTo = task.ContactEmail
 68→			} else if !strings.EqualFold(strings.TrimSpace(sendTo), strings.TrimSpace(task.ContactEmail)) {
 69→				return fmt.Errorf("--task-id %s belongs to %s, but --to was %s", task.ID, task.ContactEmail, sendTo)
 70→			}
 71→			if sendSubject == "" || sendBody == "" {
 72→				renderedSubject, renderedBody, err := sequence.RenderTaskContent(d, *task)
 73→				if err != nil {
 74→					return err
 75→				}
 76→				if sendSubject == "" {
 77→					sendSubject = renderedSubject
 78→				}
 79→				if sendBody == "" {
 80→					sendBody = renderedBody
 81→				}
 82→			}
 83→		}
 84→
 85→		if sendTo == "" {
 86→			return fmt.Errorf("recipient (--to) is required")
 87→		}
 88→		if sendSubject == "" {
 89→			return fmt.Errorf("subject (--subject) is required")
 90→		}
 91→		if sendBody == "" {
 92→			return fmt.Errorf("body (--body) is required")
 93→		}
 94→
 95→		// Send via Gmail API
 96→		sent, err := email.Send(srv, fromAddress, email.SendOptions{
 97→			To:      strings.TrimSpace(sendTo),
 98→			Cc:      strings.TrimSpace(sendCc),
 99→			Subject: sendSubject,
100→			Body:    sendBody,
101→		})
102→		if err != nil {
103→			return fmt.Errorf("send failed: %w", err)
104→		}
105→
106→		// Store the sent email locally
107→		sentAt := time.Now().UTC()
108→		if storeErr := email.StoreEmail(d, &email.RawMessage{
109→			ID:        sent.MessageID,
110→			Source:    "gmail",
111→			Direction: "outbound",
112→			ThreadID:  sent.ThreadID,
113→			Subject:   sendSubject,
114→			FromEmail: fromAddress,
115→			ToEmails:  cmdutil.RecipientsJSON(strings.TrimSpace(sendTo)),
116→			Date:      sentAt.Format(time.RFC3339),
117→			Labels:    `["SENT"]`,
118→		}); storeErr != nil {
119→			fmt.Fprintf(cmd.ErrOrStderr(), "  warning: sent but failed to store locally: %v\n", storeErr)
120→		}
121→
122→		// If --task-id, advance the sequence
123→		if sendTaskID != "" {
124→			sendType := sequence.NormalizeSendType(sendSendType)
125→			if err := sequence.UpdateTaskSendState(d, sendTaskID, sequence.TaskSendStatusSent, sent.MessageID, "", ""); err != nil {
126→				fmt.Fprintf(cmd.ErrOrStderr(), "  warning: sent but failed to update task: %v\n", err)
127→			}
128→			if _, err := sequence.AdvanceTaskAfterSend(d, sequence.AdvanceOptions{
129→				TaskID:    sendTaskID,
130→				ThreadID:  sent.ThreadID,
131→				MessageID: sent.MessageID,
132→				SentAt:    sentAt,
133→			}); err != nil {
134→				fmt.Fprintf(cmd.ErrOrStderr(), "  warning: sent but failed to advance sequence: %v\n", err)
135→			}
136→			if err := sequence.LogSendAttempt(d, sequence.SendAttemptOptions{
137→				EnrollmentID: "",
138→				TaskID:       sendTaskID,
139→				ContactEmail: strings.TrimSpace(sendTo),
140→				SendType:     sendType,
141→				Status:       "sent",
142→				Subject:      sendSubject,
143→				MessageID:    sent.MessageID,
144→				AttemptedAt:  sentAt,
145→			}); err != nil {
146→				fmt.Fprintf(cmd.ErrOrStderr(), "  warning: sent but failed to log attempt: %v\n", err)
147→			}
148→		}
149→
150→		// Sequence enrollment for first touch
151→		if sendSequence != "" {
152→			enrollmentID, enrollErr := enrollInSequence(sent, fromAddress, sentAt)
153→			if enrollErr != nil {
154→				fmt.Fprintf(cmd.ErrOrStderr(), "  warning: sent but failed to enroll in sequence: %v\n", enrollErr)
155→			} else {
156→				fmt.Printf("  ↳ Enrolled in sequence %s (%s)\n", sendSequence, enrollmentID)
157→			}
158→		}
159→
160→		fmt.Printf("  \033[32m✓\033[0m Sent to %s (message ID: %s)\n", sendTo, sent.MessageID)
161→		return nil
162→	},
163→}
