185→// parseDays extracts day count from a duration string like "3d" or "72h".
186→func parseDays(delay string) int {
187→	delay = strings.TrimSpace(delay)
188→	if delay == "" || delay == "0s" {
189→		return 0
190→	}
191→	if strings.HasSuffix(delay, "d") {
192→		var d int
193→		fmt.Sscanf(delay, "%dd", &d)
194→		return d
195→	}
196→	if strings.HasSuffix(delay, "h") {
197→		var h int
198→		fmt.Sscanf(delay, "%dh", &h)
199→		return h / 24
200→	}
201→	return 3
202→}
