  8→func AnalyticsSummary(d *sql.DB, now time.Time) (*SequenceAnalyticsSummary, error) {
  9→	if now.IsZero() {
 10→		now = time.Now()
 11→	}
 12→
 13→	summary := &SequenceAnalyticsSummary{
 14→		GeneratedAt:  now.UTC().Format(time.RFC3339),
 15→		ReplyClasses: map[string]int{},
 16→	}
 17→
 18→	if err := d.QueryRow(`SELECT COUNT(*) FROM sequence_enrollments WHERE status = ?`, StatusActive).Scan(&summary.ActiveEnrollments); err != nil {
 19→		return nil, err
 20→	}
 21→	if err := d.QueryRow(`SELECT COUNT(*) FROM sequence_enrollments WHERE status = ?`, StatusPaused).Scan(&summary.PausedEnrollments); err != nil {
 22→		return nil, err
 23→	}
 24→	if err := d.QueryRow(`SELECT COUNT(*) FROM sequence_enrollments WHERE status = ?`, StatusCompleted).Scan(&summary.CompletedEnrollments); err != nil {
 25→		return nil, err
 26→	}
 27→	if err := d.QueryRow(`SELECT COUNT(*) FROM sequence_enrollments WHERE status = ?`, StatusStopped).Scan(&summary.StoppedEnrollments); err != nil {
 28→		return nil, err
 29→	}
 30→	if err := d.QueryRow(`SELECT COUNT(*) FROM follow_up_tasks WHERE status = ?`, TaskStatusOpen).Scan(&summary.OpenTasks); err != nil {
 31→		return nil, err
 32→	}
 33→	if err := d.QueryRow(`SELECT COUNT(*) FROM follow_up_tasks WHERE status = ?`, TaskStatusCompleted).Scan(&summary.CompletedTasks); err != nil {
 34→		return nil, err
 35→	}
 36→	if err := d.QueryRow(`SELECT COUNT(*) FROM follow_up_tasks WHERE status = ?`, TaskStatusCanceled).Scan(&summary.CanceledTasks); err != nil {
 37→		return nil, err
 38→	}
 39→	if err := d.QueryRow(`SELECT COUNT(*) FROM reply_events`).Scan(&summary.ReplyCount); err != nil {
 40→		return nil, err
 41→	}
 42→	if err := d.QueryRow(`SELECT COUNT(*) FROM suppressions`).Scan(&summary.SuppressionCount); err != nil {
 43→		return nil, err
 44→	}
 45→
 46→	replyRows, err := d.Query(`SELECT classification, COUNT(*) FROM reply_events GROUP BY classification ORDER BY COUNT(*) DESC`)
 47→	if err != nil {
 48→		return nil, err
 49→	}
 50→	defer replyRows.Close()
 51→	for replyRows.Next() {
 52→		var classification string
 53→		var count int
 54→		if err := replyRows.Scan(&classification, &count); err != nil {
 55→			return nil, err
 56→		}
 57→		summary.ReplyClasses[classification] = count
 58→	}
 59→	if err := replyRows.Err(); err != nil {
 60→		return nil, err
 61→	}
 62→
 63→	sequenceRows, err := d.Query(`
 64→		SELECT
 65→			e.sequence_name,
 66→			COUNT(DISTINCT CASE WHEN e.status = 'active' THEN e.id END),
 67→			COUNT(DISTINCT CASE WHEN e.status = 'paused' THEN e.id END),
 68→			COUNT(DISTINCT CASE WHEN e.status = 'completed' THEN e.id END),
 69→			COUNT(DISTINCT CASE WHEN e.status = 'stopped' THEN e.id END),
 70→			COUNT(DISTINCT CASE WHEN t.status = 'open' THEN t.id END),
 71→			COUNT(DISTINCT r.id)
 72→		FROM sequence_enrollments e
 73→		LEFT JOIN follow_up_tasks t ON t.enrollment_id = e.id
 74→		LEFT JOIN reply_events r ON r.enrollment_id = e.id
 75→		GROUP BY e.sequence_name
 76→		ORDER BY e.sequence_name ASC`)
 77→	if err != nil {
 78→		return nil, err
 79→	}
 80→	defer sequenceRows.Close()
 81→	for sequenceRows.Next() {
 82→		var item SequencePerformance
 83→		if err := sequenceRows.Scan(
 84→			&item.Name,
 85→			&item.ActiveEnrollments,
 86→			&item.PausedEnrollments,
 87→			&item.CompletedEnrollments,
 88→			&item.StoppedEnrollments,
 89→			&item.OpenTasks,
 90→			&item.ReplyCount,
 91→		); err != nil {
 92→			return nil, err
 93→		}
 94→		summary.BySequence = append(summary.BySequence, item)
 95→	}
 96→	if err := sequenceRows.Err(); err != nil {
 97→		return nil, err
 98→	}
 99→
100→	mailboxRows, err := d.Query(`
101→		SELECT
102→			m.email,
103→			COALESCE(u.first_touches_sent, 0),
104→			COALESCE(u.follow_ups_sent, 0),
105→			COALESCE(u.replies_sent, 0),
106→			SUM(CASE WHEN e.status = 'active' THEN 1 ELSE 0 END),
107→			SUM(CASE WHEN e.status = 'paused' THEN 1 ELSE 0 END),
108→			SUM(CASE WHEN e.status = 'completed' THEN 1 ELSE 0 END)
109→		FROM mailboxes m
110→		LEFT JOIN mailbox_daily_usage u
111→			ON u.mailbox_id = m.id AND u.usage_day = ?
112→		LEFT JOIN sequence_enrollments e ON e.mailbox_id = m.id
113→		GROUP BY m.id, m.email, u.first_touches_sent, u.follow_ups_sent, u.replies_sent
114→		ORDER BY m.email ASC`,
115→		dayKey(now),
116→	)
117→	if err != nil {
118→		return nil, err
119→	}
120→	defer mailboxRows.Close()
121→	for mailboxRows.Next() {
122→		var item MailboxPerformance
123→		if err := mailboxRows.Scan(
124→			&item.MailboxEmail,
125→			&item.FirstTouchesSent,
126→			&item.FollowUpsSent,
127→			&item.RepliesSent,
128→			&item.ActiveEnrollments,
129→			&item.PausedEnrollments,
130→			&item.CompletedEnrollments,
131→		); err != nil {
132→			return nil, err
133→		}
134→		summary.ByMailbox = append(summary.ByMailbox, item)
135→	}
136→	if err := mailboxRows.Err(); err != nil {
137→		return nil, err
138→	}
139→
140→	return summary, nil
141→}
