216→func buildSyncBannerLine(report *sessionSyncReport) string {
217→	if report == nil || !report.Attempted {
218→		return ""
219→	}
220→	if report.Error != "" {
221→		return "Remote sync unavailable — using last local state"
222→	}
223→	if report.RowsUpserted == 0 {
224→		return ""
225→	}
226→
227→	parts := []string{}
228→	if report.Delta != nil {
229→		if report.Delta.TasksSent > 0 {
230→			parts = append(parts, fmt.Sprintf("%d follow-up%s sent", report.Delta.TasksSent, pluralSuffix(report.Delta.TasksSent)))
231→		}
232→		if report.Delta.RepliesNeedingAttention > 0 {
233→			parts = append(parts, fmt.Sprintf("%d repl%s need attention", report.Delta.RepliesNeedingAttention, pluralSuffix(report.Delta.RepliesNeedingAttention, "y", "ies")))
234→		}
235→		if report.Delta.TasksFailed > 0 {
236→			parts = append(parts, fmt.Sprintf("%d send failure%s", report.Delta.TasksFailed, pluralSuffix(report.Delta.TasksFailed)))
237→		}
238→		if len(report.Delta.AuthExpiredMailboxes) > 0 {
239→			parts = append(parts, fmt.Sprintf("%d mailbox reconnect%s needed", len(report.Delta.AuthExpiredMailboxes), pluralSuffix(len(report.Delta.AuthExpiredMailboxes))))
240→		}
241→	}
242→	if len(parts) == 0 {
243→		return fmt.Sprintf("Synced %d remote update%s", report.RowsUpserted, pluralSuffix(report.RowsUpserted))
244→	}
245→	return "While you were away: " + strings.Join(parts, " | ")
246→}
