141→func gatherStatus() *sessionStatus {
142→	s := &sessionStatus{
143→		settings: make(map[string]string),
144→	}
145→
146→	// Load config (graceful — may not exist)
147→	cfg, err := project.Load()
148→	if err == nil {
149→		s.configLoaded = true
150→		s.setupCompleted = cfg.SetupCompleted
151→		s.connectors = cfg.Connectors
152→		if cfg.Settings != nil {
153→			s.settings = cfg.Settings
154→		}
155→	}
156→
157→	// Load DB stats (graceful — may not exist)
158→	if !db.Exists() {
159→		return s
160→	}
161→	d, err := db.Open()
162→	if err != nil {
163→		return s
164→	}
165→	defer d.Close()
166→
167→	stats, err := email.Stats(d)
168→	if err == nil {
169→		s.emailTotal = stats.Total
170→		s.outboundTotal = stats.ByClass["outbound"]
171→	}
172→
173→	weekly, err := email.ThisWeek(d)
174→	if err == nil {
175→		s.weeklyStats = weekly
176→	}
177→
178→	skills, err := session.ListSkills(d)
179→	if err == nil {
180→		s.skillCount = len(skills)
181→		for _, sk := range skills {
182→			s.skillNames = append(s.skillNames, sk.SkillName)
183→		}
184→	}
185→
186→	// Contact count (graceful)
187→	d.QueryRow("SELECT COUNT(*) FROM contacts").Scan(&s.contactCount)
188→
189→	// Learning count (graceful)
190→	d.QueryRow("SELECT COUNT(*) FROM learnings").Scan(&s.learningCount)
191→
192→	memories, err := session.ListStrategicMemory(d, 3)
193→	if err == nil {
194→		s.recentStrategicMemory = memories
195→	}
196→
197→	staleSkills, err := session.ListStaleSkills(d, 5)
198→	if err == nil {
199→		s.staleSkills = staleSkills
200→	}
201→
202→	return s
203→}
