 63→// runInit is the shared init logic used by both the root command and the hidden init alias.
 64→func runInit(cmd *cobra.Command, args []string) error {
 65→	dirCreated := ""
 66→
 67→	if len(args) == 1 {
 68→		dir := args[0]
 69→		if err := os.MkdirAll(dir, 0755); err != nil {
 70→			return fmt.Errorf("failed to create directory %s: %w", dir, err)
 71→		}
 72→		abs, err := filepath.Abs(dir)
 73→		if err != nil {
