 81→		// No directory arg: only init if current dir is empty or already initialized
 82→		empty, _ := project.IsDirEmpty(".")
 83→		alreadyInit := project.IsNurgeProject(".")
 84→		if !empty && !alreadyInit {
 85→			return cmd.Help()
