 90→	if !initForce {
 91→		empty, err := project.IsDirEmpty(".")
 92→		if err != nil {
 93→			return err
 94→		}
 95→		if !empty && !project.IsNurgeProject(".") {
 96→			return fmt.Errorf("this directory isn't empty. Run: nurge <folder-name>")
 97→		}
 98→	}
