166→// isKnownCommand checks if name matches any registered subcommand.
167→func isKnownCommand(name string) bool {
168→	for _, c := range rootCmd.Commands() {
169→		if c.Name() == name {
170→			return true
171→		}
172→		for _, alias := range c.Aliases {
173→			if alias == name {
174→				return true
175→			}
176→		}
177→	}
178→	return name == "help" || name == "completion"
