181→func Execute() error {
182→	// Allow "nurge my-outbound" as shorthand for "nurge init my-outbound".
183→	// Cobra rejects unknown subcommands before RunE runs, so we rewrite args
184→	// when the first arg isn't a known subcommand or flag.
185→	if len(os.Args) > 1 {
186→		first := os.Args[1]
187→		if !strings.HasPrefix(first, "-") && !isKnownCommand(first) {
188→			os.Args = append([]string{os.Args[0], "init"}, os.Args[1:]...)
189→		}
190→	}
191→
192→	// Start async update check before stdout wrapping (uses stderr, no interaction).
193→	type updateResult struct {
194→		info *update.UpdateInfo
195→	}
196→	updateCh := make(chan updateResult, 1)
197→	cmdName := resolveCommandName()
198→	if cmdutil.BuildVersion != "dev" && cmdName != "update" && cmdName != "version" {
199→		go func() {
200→			ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
201→			defer cancel()
202→			info, _ := update.CheckForUpdate(ctx, cmdutil.BuildVersion)
203→			updateCh <- updateResult{info: info}
204→		}()
205→	}
206→
207→	// Wrap stdout with a counting writer to measure output size.
208→	cw := metrics.NewCountingWriter(os.Stdout)
209→	rootCmd.SetOut(cw)
210→	origStdout := os.Stdout
211→	r, w, _ := os.Pipe()
212→	os.Stdout = w
213→
214→	// Copy pipe output to counting writer in background.
215→	done := make(chan struct{})
216→	go func() {
217→		buf := make([]byte, 4096)
218→		for {
219→			n, err := r.Read(buf)
220→			if n > 0 {
221→				cw.Write(buf[:n])
222→			}
223→			if err != nil {
224→				break
225→			}
226→		}
227→		close(done)
228→	}()
229→
230→	err := rootCmd.Execute()
231→
232→	// Restore stdout and flush.
233→	w.Close()
234→	<-done
235→	os.Stdout = origStdout
236→
237→	// Print update notification if available (to stderr, so --format json is clean).
238→	select {
239→	case r := <-updateCh:
240→		if r.info != nil {
241→			fmt.Fprintf(os.Stderr, "\n→ nurge %s available. Run: nurge update\n", r.info.LatestVersion)
242→		}
243→	default:
244→	}
245→
246→	// Log metrics if we're in a nurge project and this isn't the init/metrics command.
247→	if cmdName != "" && cmdName != "init" && cmdName != "metrics" && cmdName != "version" && db.Exists() {
248→		if d, dbErr := db.Open(); dbErr == nil {
249→			_ = metrics.EnsureTable(d)
250→			_ = metrics.Log(d, metrics.SessionID(), cmdName, cw.Count())
251→			d.Close()
252→		}
253→	}
254→
255→	return err
256→}
