258→// checkPendingSkillUpgrade prints a reminder if a pending skill upgrade marker exists.
259→func checkPendingSkillUpgrade() {
260→	markerPath := filepath.Join(".nurge", "pending-skill-upgrade.json")
261→	if _, err := os.Stat(markerPath); err == nil {
262→		fmt.Fprintf(os.Stderr, "→ Skill templates updated. Run /nurge:upgrade-skills in Claude Code to apply.\n")
263→	}
264→}
