266→// resolveCommandName returns the full command path (e.g. "emails list", "skills write").
267→func resolveCommandName() string {
268→	if len(os.Args) < 2 {
269→		return "init"
270→	}
271→	// Build command name from args, skipping flags.
272→	var parts []string
273→	for _, arg := range os.Args[1:] {
274→		if strings.HasPrefix(arg, "-") {
275→			break
276→		}
277→		parts = append(parts, arg)
278→	}
279→	if len(parts) == 0 {
280→		return "init"
281→	}
282→	return strings.Join(parts, " ")
283→}
