 76→
 77→	var result []MailboxStatus
 78→	for rows.Next() {
 79→		var m MailboxStatus
 80→		m.UsageDay = dayKey(now)
 81→		if err := rows.Scan(
 82→			&m.ID, &m.Email, &m.TransportEmail, &m.RotationGroup, &m.Provider, &m.Status, &m.WarmupStage, &m.WarmupStartedAt,
 83→			&m.FirstTouchDailyCap, &m.FollowUpDailyCap, &m.ReplyDailyCap, &m.MinGapMinutes,
 84→			&m.SendWindowStartHour, &m.SendWindowEndHour, &m.SendWindowTimezone,
 85→			&m.ReputationScore, &m.Priority, &m.LastUsedAt, &m.LastBounceAt,
 86→			&m.FirstTouchesSent, &m.FollowUpsSent, &m.RepliesSent,
 87→		); err != nil {
 88→			return nil, err
 89→		}
 90→		m.FirstTouchDailyCap, m.FollowUpDailyCap, m.ReplyDailyCap = effectiveCaps(m.Mailbox, now)
