253→func mailboxAndUsage(d *sql.DB, mailboxID string, now time.Time) (*Mailbox, *MailboxStatus, error) {
254→	row := d.QueryRow(`
255→		SELECT
256→			m.id, m.email, m.transport_email, m.rotation_group, m.provider, m.status, m.warmup_stage, m.warmup_started_at,
257→			m.first_touch_daily_cap, m.follow_up_daily_cap, m.reply_daily_cap, m.min_gap_minutes,
258→			m.send_window_start_hour, m.send_window_end_hour, m.send_window_timezone,
259→			m.reputation_score, m.priority, m.last_used_at, m.last_bounce_at,
260→			COALESCE(u.first_touches_sent, 0),
261→			COALESCE(u.follow_ups_sent, 0),
262→			COALESCE(u.replies_sent, 0)
263→		FROM mailboxes m
264→		LEFT JOIN mailbox_daily_usage u
265→			ON u.mailbox_id = m.id AND u.usage_day = ?
266→		WHERE m.id = ?`,
267→		dayKey(now), mailboxID,
268→	)
269→
270→	var mailbox Mailbox
271→	usage := &MailboxStatus{}
272→	if err := row.Scan(
273→		&mailbox.ID, &mailbox.Email, &mailbox.TransportEmail, &mailbox.RotationGroup, &mailbox.Provider, &mailbox.Status, &mailbox.WarmupStage, &mailbox.WarmupStartedAt,
274→		&mailbox.FirstTouchDailyCap, &mailbox.FollowUpDailyCap, &mailbox.ReplyDailyCap, &mailbox.MinGapMinutes,
275→		&mailbox.SendWindowStartHour, &mailbox.SendWindowEndHour, &mailbox.SendWindowTimezone,
276→		&mailbox.ReputationScore, &mailbox.Priority, &mailbox.LastUsedAt, &mailbox.LastBounceAt,
277→		&usage.FirstTouchesSent, &usage.FollowUpsSent, &usage.RepliesSent,
278→	); err != nil {
279→		if err == sql.ErrNoRows {
