415→func rotationCandidates(d *sql.DB, primary Mailbox, sendType, transportEmail string, now time.Time) ([]*Mailbox, error) {
416→	rows, err := d.Query(`
417→		SELECT id, email, transport_email, rotation_group, provider, status, warmup_stage, warmup_started_at,
418→			first_touch_daily_cap, follow_up_daily_cap, reply_daily_cap, min_gap_minutes,
419→			send_window_start_hour, send_window_end_hour, send_window_timezone,
420→			reputation_score, priority, last_used_at, last_bounce_at,
421→			COALESCE(u.first_touches_sent, 0), COALESCE(u.follow_ups_sent, 0), COALESCE(u.replies_sent, 0)
422→		FROM mailboxes
423→		LEFT JOIN mailbox_daily_usage u
424→			ON u.mailbox_id = mailboxes.id AND u.usage_day = ?
425→		WHERE provider = ? AND rotation_group = ?
426→		ORDER BY email ASC`,
427→		dayKey(now), primary.Provider, primary.RotationGroup,
428→	)
429→	if err != nil {
430→		return nil, err
431→	}
432→	defer rows.Close()
433→
434→	type candidate struct {
435→		mailbox          *Mailbox
436→		firstTouchesSent int
437→		followUpsSent    int
438→		repliesSent      int
439→		remaining        int
440→	}
441→
442→	var rawCandidates []candidate
443→	blocked := map[string]string{}
444→	for rows.Next() {
445→		var item Mailbox
446→		var firstTouchesSent, followUpsSent, repliesSent int
447→		if err := rows.Scan(
448→			&item.ID, &item.Email, &item.TransportEmail, &item.RotationGroup, &item.Provider, &item.Status, &item.WarmupStage, &item.WarmupStartedAt,
449→			&item.FirstTouchDailyCap, &item.FollowUpDailyCap, &item.ReplyDailyCap, &item.MinGapMinutes,
450→			&item.SendWindowStartHour, &item.SendWindowEndHour, &item.SendWindowTimezone,
451→			&item.ReputationScore, &item.Priority, &item.LastUsedAt, &item.LastBounceAt,
452→			&firstTouchesSent, &followUpsSent, &repliesSent,
453→		); err != nil {
454→			return nil, err
455→		}
456→		if !strings.EqualFold(effectiveTransportEmail(item), transportEmail) {
457→			continue
458→		}
459→		rawCandidates = append(rawCandidates, candidate{
460→			mailbox:          &item,
461→			firstTouchesSent: firstTouchesSent,
462→			followUpsSent:    followUpsSent,
463→			repliesSent:      repliesSent,
464→		})
465→	}
466→	if err := rows.Err(); err != nil {
467→		return nil, err
468→	}
469→	if err := rows.Close(); err != nil {
470→		return nil, err
471→	}
472→
473→	candidates := make([]candidate, 0, len(rawCandidates))
474→	for _, item := range rawCandidates {
475→		if err := CanSend(d, item.mailbox.ID, sendType, now); err != nil {
476→			blocked[item.mailbox.ID] = err.Error()
477→			continue
478→		}
479→
480→		firstTouchCap, followUpCap, replyCap := effectiveCaps(*item.mailbox, now)
481→		switch NormalizeSendType(sendType) {
482→		case SendTypeFirstTouch:
483→			item.remaining = remaining(firstTouchCap, item.firstTouchesSent)
484→		case SendTypeFollowUp:
485→			item.remaining = remaining(followUpCap, item.followUpsSent)
486→		case SendTypeReply:
487→			item.remaining = remaining(replyCap, item.repliesSent)
488→		default:
489→			item.remaining = -1
490→		}
491→		candidates = append(candidates, item)
492→	}
493→
494→	sort.SliceStable(candidates, func(i, j int) bool {
495→		left := candidates[i]
496→		right := candidates[j]
497→		if left.mailbox.ID == primary.ID && right.mailbox.ID != primary.ID {
498→			return true
499→		}
500→		if right.mailbox.ID == primary.ID && left.mailbox.ID != primary.ID {
501→			return false
502→		}
503→		if left.mailbox.Priority != right.mailbox.Priority {
504→			return left.mailbox.Priority > right.mailbox.Priority
505→		}
506→		if left.mailbox.ReputationScore != right.mailbox.ReputationScore {
507→			return left.mailbox.ReputationScore > right.mailbox.ReputationScore
508→		}
509→		if left.remaining != right.remaining {
510→			return left.remaining > right.remaining
511→		}
512→		leftUsed := parseOptionalTime(left.mailbox.LastUsedAt)
513→		rightUsed := parseOptionalTime(right.mailbox.LastUsedAt)
514→		if leftUsed.IsZero() != rightUsed.IsZero() {
515→			return leftUsed.IsZero()
516→		}
517→		if !leftUsed.Equal(rightUsed) {
518→			return leftUsed.Before(rightUsed)
519→		}
520→		return left.mailbox.Email < right.mailbox.Email
521→	})
522→
523→	if len(candidates) == 0 {
524→		if reason := blocked[primary.ID]; reason != "" {
525→			return nil, fmt.Errorf("%s", reason)
526→		}
527→	}
528→
529→	result := make([]*Mailbox, 0, len(candidates))
530→	for _, item := range candidates {
531→		result = append(result, item.mailbox)
532→	}
533→	return result, nil
534→}
