536→func withinSendWindow(mailbox Mailbox, now time.Time) bool {
537→	start := clampHour(mailbox.SendWindowStartHour)
538→	end := clampHour(mailbox.SendWindowEndHour)
539→	if start == end {
540→		return true
541→	}
542→
543→	loc := time.Local
544→	tz := strings.TrimSpace(mailbox.SendWindowTimezone)
545→	if tz != "" && !strings.EqualFold(tz, "local") {
546→		if loaded, err := time.LoadLocation(tz); err == nil {
547→			loc = loaded
548→		}
549→	}
550→	hour := now.In(loc).Hour()
551→	if start < end {
552→		return hour >= start && hour < end
553→	}
554→	return hour >= start || hour < end
555→}
556→
557→func effectiveTransportEmail(mailbox Mailbox) string {
558→	if strings.TrimSpace(mailbox.TransportEmail) != "" {
559→		return strings.TrimSpace(mailbox.TransportEmail)
560→	}
561→	return strings.TrimSpace(mailbox.Email)
562→}
563→
564→func effectiveCaps(mailbox Mailbox, now time.Time) (int, int, int) {
565→	if now.IsZero() {
566→		now = time.Now()
567→	}
568→	firstTouchCap := mailbox.FirstTouchDailyCap
569→	followUpCap := mailbox.FollowUpDailyCap
570→	replyCap := mailbox.ReplyDailyCap
571→
572→	switch strings.ToLower(strings.TrimSpace(mailbox.WarmupStage)) {
573→	case "warming":
574→		day := warmupDay(mailbox, now)
575→		firstTouchCap = minPositive(firstTouchCap, 3+day*2)
576→		followUpCap = minPositive(followUpCap, 6+day*4)
577→	case "ramping":
578→		day := warmupDay(mailbox, now)
579→		firstTouchCap = minPositive(firstTouchCap, 5+day*5)
580→		followUpCap = minPositive(followUpCap, 10+day*10)
581→	}
582→
583→	switch {
584→	case mailbox.ReputationScore > 0 && mailbox.ReputationScore < 70:
585→		firstTouchCap = scaledCap(firstTouchCap, 0.5)
586→		followUpCap = scaledCap(followUpCap, 0.75)
587→	case mailbox.ReputationScore > 0 && mailbox.ReputationScore < 85:
588→		firstTouchCap = scaledCap(firstTouchCap, 0.75)
589→	}
590→
591→	return firstTouchCap, followUpCap, replyCap
592→}
