 14→// loadSyncEngine creates a sync engine if Convex URL and auth are available.
 15→// Returns nil if sync is not configured.
 16→func loadSyncEngine(d *sql.DB) *nurgesync.Engine {
 17→	convexURL := strings.TrimSpace(cmdutil.GetConvexURL())
 18→	if convexURL == "" {
 19→		return nil
 20→	}
 21→	authFile, err := account.LoadAuth()
 22→	if err != nil || strings.TrimSpace(authFile.Token) == "" {
 23→		return nil
 24→	}
