 28→func attemptSessionStartSync() *sessionSyncReport {
 29→	report := &sessionSyncReport{}
 30→
 31→	if !db.Exists() {
 32→		return report
 33→	}
 34→
 35→	d, err := db.Open()
 36→	if err != nil {
 37→		report.Attempted = true
 38→		report.Error = shortSyncError(err)
 39→		return report
 40→	}
 41→	defer d.Close()
 42→
 43→	engine := loadSyncEngine(d)
 44→	if engine == nil {
 45→		return report
 46→	}
 47→
 48→	report.Attempted = true
 49→	pull, err := engine.Pull()
 50→	if err != nil {
 51→		report.Error = shortSyncError(err)
 52→		return report
 53→	}
 54→
 55→	report.RowsUpserted = pull.RowsUpserted
 56→	report.TablesUpdated = pull.TablesUpdated
 57→	report.PreviousVersion = pull.PreviousVersion
 58→	report.CurrentVersion = pull.CurrentVersion
 59→
 60→	delta, err := engine.SummarizeExecutionDelta(pull.PreviousVersion, pull.CurrentVersion)
 61→	if err == nil {
 62→		report.Delta = delta
 63→	}
 64→	memories, err := engine.DistillExecutionMemory(pull.PreviousVersion, pull.CurrentVersion)
 65→	if err == nil {
 66→		for _, memory := range memories {
 67→			_ = session.SaveStrategicMemory(d, session.StrategicMemoryInput{
 68→				Category:       memory.Category,
 69→				Summary:        memory.Summary,
 70→				AffectedSkills: memory.AffectedSkills,
 71→				Evidence:       memory.Evidence,
 72→				Source:         memory.Source,
 73→				SourceKey:      memory.SourceKey,
 74→				Priority:       memory.Priority,
 75→			})
 76→		}
 77→	}
 78→
 79→	return report
 80→}
