 82→func attemptSessionEndPush(d *sql.DB) *sessionPushReport {
 83→	report := &sessionPushReport{}
 84→
 85→	if d == nil {
 86→		return report
 87→	}
 88→
 89→	engine := loadSyncEngine(d)
 90→	if engine == nil {
 91→		return report
 92→	}
 93→
 94→	report.Attempted = true
 95→	push, err := engine.Push()
 96→	if err != nil {
 97→		report.Error = shortSyncError(err)
 98→		return report
 99→	}
100→
101→	report.RowsPushed = push.RowsPushed
102→	report.TablesScanned = push.TablesScanned
103→	return report
104→}
