package data

import (
	"database/sql"
	"encoding/json"
	"fmt"
	"os"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/internal/db"
	"github.com/usenurge/nurgesh/internal/tier"
)

var tierFormat string
var tierProspect string
var tierBatch bool
var tierLimit int
var tierShow bool

var tierCmd = &cobra.Command{
	Use:   "tier",
	Short: "Score and tier contacts based on ICP fit",
	Long:  "Score contacts using ICP fit, buying triggers, intent signals, and accessibility.\nAssigns Tier 1 (>=70), Tier 2 (>=40), or Tier 3 (<40).",
	RunE: func(cmd *cobra.Command, args []string) error {
		if !tierShow && !tierBatch && tierProspect == "" {
			return cmd.Help()
		}

		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		if tierShow {
			return runTierShow(d)
		}

		if tierProspect != "" {
			return runTierProspectCmd(d, tierProspect)
		}

		if tierBatch {
			return runTierBatch(d, tierLimit)
		}

		return nil
	},
}

func runTierProspectCmd(d *sql.DB, email string) error {
	score, err := tier.ScoreAndSave(d, email)
	if err != nil {
		return err
	}

	if tierFormat == "json" {
		enc := json.NewEncoder(os.Stdout)
		enc.SetIndent("", "  ")
		return enc.Encode(score)
	}

	fmt.Printf("  Tier %d  (score: %.1f)\n", score.Tier, score.Total)
	fmt.Printf("  ICP Fit: %.0f  |  Buying Trigger: %.0f  |  Intent: %.0f  |  Accessibility: %.0f\n",
		score.ICPFit, score.BuyingTrigger, score.IntentSignal, score.Accessibility)
	if len(score.Reasons) > 0 {
		fmt.Println("  Reasons:")
		for _, r := range score.Reasons {
			fmt.Printf("    - %s\n", r)
		}
	}
	return nil
}

func runTierShow(d *sql.DB) error {
	dist, err := tier.Distribution(d)
	if err != nil {
		return err
	}

	if tierFormat == "json" {
		enc := json.NewEncoder(os.Stdout)
		enc.SetIndent("", "  ")
		return enc.Encode(dist)
	}

	fmt.Printf("  Tier Distribution (%d contacts)\n", dist.Total)
	fmt.Printf("  ──────────────────────────────\n")
	fmt.Printf("  Tier 1 (hot):       %d\n", dist.Tier1)
	fmt.Printf("  Tier 2 (warm):      %d\n", dist.Tier2)
	fmt.Printf("  Tier 3 (cold):      %d\n", dist.Tier3)
	fmt.Printf("  Unscored:           %d\n", dist.Unscored)
	return nil
}

func runTierBatch(d *sql.DB, limit int) error {
	results, err := tier.BatchScore(d, limit)
	if err != nil {
		return err
	}

	if tierFormat == "json" {
		enc := json.NewEncoder(os.Stdout)
		enc.SetIndent("", "  ")
		return enc.Encode(results)
	}

	if len(results) == 0 {
		fmt.Println("  No contacts to score.")
		return nil
	}

	fmt.Printf("  Scored %d contact(s):\n", len(results))
	for _, r := range results {
		label := "cold"
		if r.Score.Tier == 1 {
			label = "hot"
		} else if r.Score.Tier == 2 {
			label = "warm"
		}
		name := r.Name
		if name == "" {
			name = r.Email
		}
		fmt.Printf("    [T%d %s] %s  (%.1f)\n", r.Score.Tier, label, name, r.Score.Total)
	}
	return nil
}

func init() {
	tierCmd.Flags().StringVar(&tierFormat, "format", "", "Output format (json)")
	tierCmd.Flags().StringVar(&tierProspect, "prospect", "", "Score a single contact by email")
	tierCmd.Flags().BoolVar(&tierBatch, "batch", false, "Score all unscored contacts")
	tierCmd.Flags().IntVar(&tierLimit, "limit", 50, "Max contacts to score in batch mode")
	tierCmd.Flags().BoolVar(&tierShow, "show", false, "Show tier distribution")
}

