// isKnownCommand checks if name matches any registered subcommand.
func isKnownCommand(name string) bool {
	for _, c := range rootCmd.Commands() {
		if c.Name() == name {
			return true
		}
		for _, alias := range c.Aliases {
			if alias == name {
				return true
			}
		}
	}
	return name == "help" || name == "completion"
}

func Execute() error {
	// Allow "nurge my-outbound" as shorthand for "nurge init my-outbound".
	// Cobra rejects unknown subcommands before RunE runs, so we rewrite args
	// when the first arg isn't a known subcommand or flag.
	if len(os.Args) > 1 {
		first := os.Args[1]
		if !strings.HasPrefix(first, "-") && !isKnownCommand(first) {
			os.Args = append([]string{os.Args[0], "init"}, os.Args[1:]...)
		}
	}

	// Start async update check before stdout wrapping (uses stderr, no interaction).
	type updateResult struct {
		info *update.UpdateInfo
	}
	updateCh := make(chan updateResult, 1)
	cmdName := resolveCommandName()
	if cmdutil.BuildVersion != "dev" && cmdName != "update" && cmdName != "version" {
		go func() {
			ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
			defer cancel()
			info, _ := update.CheckForUpdate(ctx, cmdutil.BuildVersion)
			updateCh <- updateResult{info: info}
		}()
	}

	// Wrap stdout with a counting writer to measure output size.
	cw := metrics.NewCountingWriter(os.Stdout)
	rootCmd.SetOut(cw)
	origStdout := os.Stdout
	r, w, _ := os.Pipe()
	os.Stdout = w

	// Copy pipe output to counting writer in background.
	done := make(chan struct{})
	go func() {
		buf := make([]byte, 4096)
		for {
			n, err := r.Read(buf)
			if n > 0 {
				cw.Write(buf[:n])
			}
			if err != nil {
				break
			}
		}
		close(done)
	}()

