	// Wrap stdout with a counting writer to measure output size.
	cw := metrics.NewCountingWriter(os.Stdout)
	rootCmd.SetOut(cw)
	origStdout := os.Stdout
	r, w, _ := os.Pipe()
	os.Stdout = w

	// Copy pipe output to counting writer in background.
	done := make(chan struct{})
	go func() {
		buf := make([]byte, 4096)
		for {
			n, err := r.Read(buf)
			if n > 0 {
				cw.Write(buf[:n])
			}
			if err != nil {
				break
			}
		}
		close(done)
	}()

	err := rootCmd.Execute()

	// Restore stdout and flush.
	w.Close()
	<-done
	os.Stdout = origStdout

	// Print update notification if available (to stderr, so --format json is clean).
	select {
	case r := <-updateCh:
		if r.info != nil {
			fmt.Fprintf(os.Stderr, "\n→ nurge %s available. Run: nurge update\n", r.info.LatestVersion)
		}
	default:
	}

	// Log metrics if we're in a nurge project and this isn't the init/metrics command.
	if cmdName != "" && cmdName != "init" && cmdName != "metrics" && cmdName != "version" && db.Exists() {
		if d, dbErr := db.Open(); dbErr == nil {
			_ = metrics.EnsureTable(d)
			_ = metrics.Log(d, metrics.SessionID(), cmdName, cw.Count())
			d.Close()
		}
	}

	return err
}

// checkPendingSkillUpgrade prints a reminder if a pending skill upgrade marker exists.
func checkPendingSkillUpgrade() {
	markerPath := filepath.Join(".nurge", "pending-skill-upgrade.json")
	if _, err := os.Stat(markerPath); err == nil {
		fmt.Fprintf(os.Stderr, "→ Skill templates updated. Run /nurge:upgrade-skills in Claude Code to apply.\n")
	}
}

// resolveCommandName returns the full command path (e.g. "emails list", "skills write").
func resolveCommandName() string {
	if len(os.Args) < 2 {
		return "init"
	}
	// Build command name from args, skipping flags.
	var parts []string
	for _, arg := range os.Args[1:] {
		if strings.HasPrefix(arg, "-") {
			break
		}
		parts = append(parts, arg)
	}
	if len(parts) == 0 {
		return "init"
	}
	return strings.Join(parts, " ")
}

