		return ""
	}
	message := strings.TrimSpace(err.Error())
	if len(message) > 120 {
		return message[:117] + "..."
	}
	return message
}

func pluralSuffix(count int, forms ...string) string {
	if len(forms) == 2 {
		if count == 1 {
			return forms[0]
		}
		return forms[1]
	}
	if count == 1 {
		return ""
	}
	return "s"
}

func capitalize(s string) string {
	if s == "" {
		return s
	}
	return strings.ToUpper(s[:1]) + s[1:]
}

